### Configure Tabs Field with Nested Fields in Payload CMS Collection

Source: https://github.com/payloadcms/payload/blob/main/docs/fields/tabs.mdx

Defines a CollectionConfig with a tabs field containing two tab groups. The first tab includes a simple text field, while the second tab demonstrates named tab access with an interface name for TypeScript support. Named tabs allow accessing nested fields via dot notation (e.g., tabTwo.numberField).

```typescript
import type { CollectionConfig } from 'payload'

export const ExampleCollection: CollectionConfig = {
  slug: 'example-collection',
  fields: [
    {
      type: 'tabs', // required
      tabs: [
        // required
        {
          label: 'Tab One Label', // required
          description: 'This will appear within the tab above the fields.',
          fields: [
            // required
            {
              name: 'someTextField',
              type: 'text',
              required: true,
            },
          ],
        },
        {
          name: 'tabTwo',
          label: 'Tab Two Label', // required
          interfaceName: 'TabTwo', // optional (`name` must be present)
          fields: [
            // required
            {
              name: 'numberField', // accessible via tabTwo.numberField
              type: 'number',
              required: true,
            },
          ],
        },
      ],
    },
  ],
}
```

